sequence.script:
function clean(data) {

    if (data === null || data === "") {
        return null;
    }

    // Handle Array
    if (Array.isArray(data)) {
        var newArray = [];
        for (var i = 0; i < data.length; i++) {
            var cleanedItem = clean(data[i]);
            if (cleanedItem !== null) {
                newArray.push(cleanedItem);
            }
        }
        return newArray;
    }

    // Handle Object
    if (typeof data === "object") {
        var newObj = {};
        for (var key in data) {
            if (data.hasOwnProperty(key)) {
                var value = data[key];

                if (value !== null && value !== "") {
                    var cleanedValue = clean(value);
                    if (cleanedValue !== null) {
                        newObj[key] = cleanedValue;
                    }
                }
            }
        }
        return newObj;
    }

    // Primitive (number, boolean, etc.)
    return data;
}

// Get payload as JSON
var payload = mc.getPayloadJSON();

// Clean it
var cleanedPayload = clean(payload);

// Set back to message context
mc.setPayloadJSON(cleanedPayload);
